  server2.tool("run_flow", "Trigger a manual flow run. Set wait=true to poll until completion.", { env: external_exports.string().optional().describe("Environment ID"), flow: external_exports.string().describe("Flow ID"), body: external_exports.record(external_exports.unknown()).optional().describe("Trigger body JSON"), wait: external_exports.boolean().optional().describe("Wait for completion (default false)"), timeout: external_exports.number().optional().describe("Wait timeout seconds (default 60)") }, { readOnlyHint: false, title: "Run Flow" }, async ({ env, flow, body, wait, timeout }, extra) => {
    try {
      const envId = ctx.resolveEnv(env);
      const c = ctx.getClient();
      if (wait) {
        const prog = progress(extra);
        await prog.send(0, 100, `Triggering flow ${flow}\u2026`);
        let elapsed = 0;
        const totalSec = timeout ?? 60;
        const hb = prog.enabled ? setInterval(() => {
          elapsed += 2;
          void prog.send(Math.min(99, Math.floor(elapsed / totalSec * 100)), 100, `Polling run status\u2026 (${elapsed}s / ${totalSec}s)`);
        }, 2e3) : null;
        try {
          const triggerWallClock = Date.now() - 5e3;
          let triggerResult;
          if (body) {
            try {
              triggerResult = await c.runFlowViaCallback(envId, flow, body);
            } catch (e) {
              if (String(e?.message ?? "").match(/CallbackUrl|ListCallbackUrl/i)) {
                triggerResult = await c.runFlow(envId, flow);
              } else
                throw e;
            }
          } else {
            triggerResult = await c.runFlow(envId, flow);
          }
          const deadline = Date.now() + (timeout ? timeout * 1e3 : 6e4);
          let finalRun = null;
          while (Date.now() < deadline) {
            await new Promise((r2) => setTimeout(r2, 2e3));
            try {
              const runs = await c.getRunHistory(envId, flow, { top: 3 });
              const recent = (runs ?? []).find((r2) => new Date(r2.properties?.startTime ?? 0).getTime() > triggerWallClock);
              if (recent && recent.properties?.status !== "Running") {
                finalRun = recent;
                break;
              }
              if (recent)
                finalRun = recent;
            } catch {
            }
          }
          let actions = [];
          if (finalRun?.name) {
            try {
              const acts = await c.getRunActionDetails(envId, flow, finalRun.name);
              actions = (acts ?? []).map((a) => ({
                name: a.name,
                status: a.properties?.status,
                durationMs: a.properties?.startTime && a.properties?.endTime ? new Date(a.properties.endTime).getTime() - new Date(a.properties.startTime).getTime() : null,
                errorCode: a.properties?.error?.code
              }));
            } catch {
            }
          }
          const result = {
            triggered: true,
            runId: finalRun?.name,
            status: finalRun?.properties?.status ?? "Unknown",
            startTime: finalRun?.properties?.startTime,
            endTime: finalRun?.properties?.endTime,
            errorCode: finalRun?.properties?.error?.code,
            errorMessage: finalRun?.properties?.error?.message,
            actions
          };
          await prog.send(100, 100, `Run completed: status=${result.status}`);
          return safeResult(result);
        } finally {
          if (hb)
            clearInterval(hb);
        }
      }
      let r;
      if (body) {
        try {
          r = await c.runFlowViaCallback(envId, flow, body);
        } catch (e) {
          if (e?.message?.includes("CallbackUrl") || e?.message?.includes("ListCallbackUrl")) {
            r = await c.runFlow(envId, flow);
          } else
            throw e;
        }
      } else {
        r = await c.runFlow(envId, flow);
      }
      return safeResult(r ?? { triggered: true });
    } catch (e) {
      return safeError(e);
    }
  });
